// ============================================================
// SECURE LOG ENTRY
// ============================================================

class LogEntry {
  constructor(level, category, message, data = null) {
    this.id = LogEntry.generateId();
    this.timestamp = new Date().toISOString();
    this.level = level;
    this.category = category;
    this.message = message;
    this.data = data ? DataSanitizer.sanitize(data) : null;
    // Do NOT log device-specific identifiers or user IDs directly
    this.sessionSegment = LogEntry.getSessionSegment();
  }

  static _counter = 0;
  static _sessionSegment = null;

  static generateId() {
    LogEntry._counter += 1;
    return `${Date.now()}-${LogEntry._counter}`;
  }

  static getSessionSegment() {
    // Use a non-identifying session segment for log correlation
    if (!LogEntry._sessionSegment) {
      LogEntry._sessionSegment = Math.random().toString(36).substring(2, 10);
    }
    return LogEntry._sessionSegment;
  }

  toJSON() {
    return {
      id: this.id,
      ts: this.timestamp,
      lvl: this.level,
      cat: this.category,
      msg: this.message,
      data: this.data,
      sess: this.sessionSegment,
    };
  }
}

