function tryParseJSON(str) {
  try {
    return JSON.parse(str);
  } catch {
    return str;
  }
}

// ============================================================
// NETWORK INTERCEPTOR
// ============================================================

class NetworkInterceptor {
  constructor(logger) {
    this.logger = logger;
    this.originalFetch = null;
    this.originalXHROpen = null;
    this.originalXHRSend = null;
  }

  install() {
    this.interceptFetch();
    this.interceptXHR();
    this.logger.info('SYSTEM', 'Network interceptor installed');
  }

  interceptFetch() {
    this.originalFetch = global.fetch;
    const logger = this.logger;

    global.fetch = async function (input, init = {}) {
      const url = typeof input === 'string' ? input : input.url;
      const method = init.method || (typeof input === 'object' ? input.method : 'GET') || 'GET';
      const startTime = Date.now();

      const config = {
        method: method.toUpperCase(),
        url,
        headers: init.headers || {},
        body: init.body,
      };

      logger.logNetworkRequest(config);

      try {
        const response = await this.originalFetch.call(global, input, init);
        const duration = Date.now() - startTime;

        // Clone response to read body without consuming it
        const clonedResponse = response.clone();
        let responseData;
        try {
          responseData = await clonedResponse.text();
        } catch {
          responseData = '[UNREADABLE_BODY]';
        }

        const responseHeaders = {};
        if (response.headers?.forEach) {
          response.headers.forEach((value, key) => {
            responseHeaders[key] = value;
          });
        }

        logger.logNetworkResponse(config, {
          status: response.status,
          statusText: response.statusText,
          headers: responseHeaders,
          data: responseData,
        }, duration);

        return response;
      } catch (error) {
        const duration = Date.now() - startTime;
        logger.logNetworkError(config, error, duration);
        throw error;
      }
    }.bind({ originalFetch: this.originalFetch });
  }

  interceptXHR() {
    const logger = this.logger;
    const OriginalXHR = global.XMLHttpRequest;

    if (!OriginalXHR) return;

    const originalOpen = OriginalXHR.prototype.open;
    const originalSend = OriginalXHR.prototype.send;
    const originalSetRequestHeader = OriginalXHR.prototype.setRequestHeader;

    OriginalXHR.prototype.open = function (method, url, ...args) {
      this._debugLogConfig = {
        method: method.toUpperCase(),
        url,
        headers: {},
        startTime: null,
      };
      return originalOpen.call(this, method, url, ...args);
    };

    OriginalXHR.prototype.setRequestHeader = function (key, value) {
      if (this._debugLogConfig) {
        this._debugLogConfig.headers[key] = value;
      }
      return originalSetRequestHeader.call(this, key, value);
    };

    OriginalXHR.prototype.send = function (body) {
      if (this._debugLogConfig) {
        this._debugLogConfig.body = body;
        this._debugLogConfig.startTime = Date.now();

        logger.logNetworkRequest(this._debugLogConfig);

        const config = { ...this._debugLogConfig };

        this.addEventListener('load', function () {
          const duration = Date.now() - config.startTime;
          logger.logNetworkResponse(config, {
            status: this.status,
            statusText: this.statusText,
            headers: parseXHRHeaders(this.getAllResponseHeaders()),
            data: this.responseText,
          }, duration);
        });

        this.addEventListener('error', function () {
          const duration = Date.now() - config.startTime;
          logger.logNetworkError(config, new Error('XHR Error'), duration);
        });

        this.addEventListener('timeout', function () {
          const duration = Date.now() - config.startTime;
          logger.logNetworkError(config, new Error('XHR Timeout'), duration);
        });
      }

      return originalSend.call(this, body);
    };
  }

  uninstall() {
    if (this.originalFetch) {
      global.fetch = this.originalFetch;
    }
  }
}

function parseXHRHeaders(headerStr) {
  const headers = {};
  if (!headerStr) return headers;

  const pairs = headerStr.trim().split('\r\n');
  for (const pair of pairs) {
    const index = pair.indexOf(': ');
    if (index > 0) {
      headers[pair.substring(0, index)] = pair.substring(index + 2);
    }
  }
  return headers;
}

// ============================================================
// ASYNC STORAGE WRAPPER
// ============================================================

class SecureStorageWrapper {
  constructor(logger) {
    this.logger = logger;
  }

  async getItem(key) {
    try {
      const value = await AsyncStorage.getItem(key);
      this.logger.logStorageGet(key, value);
      return value;
    } catch (error) {
      this.logger.logStorageGet(key, null, error);
      throw error;
    }
  }

  async setItem(key, value) {
    try {
      await AsyncStorage.setItem(key, value);
      this.logger.logStorageSet(key, value);
    } catch (error) {
      this.logger.logStorageSet(key, value, error);
      throw error;
    }
  }

  async removeItem(key) {
    try {
      await AsyncStorage.removeItem(key);
      this.logger.logStorageRemove(key);
    } catch (error) {
      this.logger.logStorageRemove(key, error);
      throw error;
    }
  }

  async multiGet(keys) {
    try {
      const result = await AsyncStorage.multiGet(keys);
      for (const [key, value] of result) {
        this.logger.logStorageGet(key, value);
      }
      return result;
    } catch (error) {
      this.logger.error('STORAGE', 'multiGet failed', {
        keyCount: keys.length,
        error: error.message,
      });
      throw error;
    }
  }

  async multiSet(keyValuePairs) {
    try {
      await AsyncStorage.multiSet(keyValuePairs);
      for (const [key, value] of keyValuePairs) {
        this.logger.logStorageSet(key, value);
      }
    } catch (error) {
      this.logger.error('STORAGE', 'multiSet failed', {
        keyCount: keyValuePairs.length,
        error: error.message,
      });
      throw error;
    }
  }

  async clear() {
    try {
      await AsyncStorage.clear();
      this.logger.info('STORAGE', 'AsyncStorage cleared');
    } catch (error) {
      this.logger.error('STORAGE', 'AsyncStorage clear failed', {
        error: error.message,
      });
      throw error;
    }
  }
}

// ============================================================
// REDUX/STATE MIDDLEWARE
// ============================================================

function createStateLoggerMiddleware(logger, storeName = 'Redux') {
  return (store) => (next) => (action) => {
    const prevState = store.getState();
    const result = next(action);
    const nextState = store.getState();

    logger.logStateChange(
      storeName,
      action.type,
      prevState,
      nextState
    );

    return result;
  };
}

// ============================================================
// REACT ERROR BOUNDARY INTEGRATION
// ============================================================

function createErrorBoundaryHandler(logger) {
  return {
    onError: (error, componentStack) => {
      logger.logCrash(error, componentStack);
    },
  };
}

// ============================================================
// SINGLETON INSTANCE & EXPORTS
// ============================================================

const logger = new DebugLogger();
const networkInterceptor = new NetworkInterceptor(logger);
const secureStorage = new SecureStorageWrapper(logger);

async function initializeDebugModule() {
  await logger.initialize();
  networkInterceptor.install();
  return {
    logger,
    secureStorage,
    networkInterceptor,
  };
}

export {
  DebugLogger,
  DataSanitizer,
  NetworkInterceptor,
  SecureStorageWrapper,
  LogLevel,
  LogEntry,
  createStateLoggerMiddleware,
  createErrorBoundaryHandler,
  initializeDebugModule,
  logger,
  networkInterceptor,
  secureStorage,
};

export default logger;